// 准备 Athena 查询参数
const sqlQuery = `SELECT id, uid, merchant_id, game_id, game_code, result, currency, ROUND(CAST(amount AS DOUBLE), 2) AS amount, ROUND(CAST(pay_out AS DOUBLE), 2) AS pay_out, multiplier, balance, detail, DATE_FORMAT(FROM_UNIXTIME(created_at / 1000), '%Y-%m-%d %H:%i:%s') AS created_at, DATE_FORMAT(FROM_UNIXTIME(updated_at / 1000), '%Y-%m-%d %H:%i:%s') AS updated_at FROM game_records WHERE provider = 'gp' AND merchant = '1737978166' AND id in ('1976423513265401856','1976422629802373120','1976437176340557824') AND updated_at BETWEEN TO_UNIXTIME(PARSE_DATETIME('2025-10-01 00:00:00', 'yyyy-MM-dd HH:mm:ss')) * 1000 AND TO_UNIXTIME(PARSE_DATETIME('2025-10-30 23:59:59', 'yyyy-MM-dd HH:mm:ss')) * 1000`;

// AWS 配置
const awsConfig = {
  region: 'us-west-2',
  accessKeyId: 'AKIAQQJLCWBOOKC7J6ZI',
  secretAccessKey: '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'
};

// Athena 配置
const athenaConfig = {
  database: 'gmp',
  outputLocation: 's3://aws-athena-query-results-us-west-2-034986963036/',
  workGroup: 'primary'
};

// 生成 AWS 签名所需的参数
const timestamp = new Date().toISOString().replace(/[\-:]|\.\d{3}/g, '');
const date = timestamp.substr(0, 8);

return {
  json: {
    sqlQuery,
    awsConfig,
    athenaConfig,
    timestamp,
    date,
    status: 'ready'
  }
};

// 生成 AWS 签名
const crypto = require('crypto');
const { awsConfig, athenaConfig, sqlQuery, timestamp, date } = $json;

// 创建请求参数
const requestParams = {
  QueryString: sqlQuery,
  QueryExecutionContext: {
    Database: athenaConfig.database
  },
  ResultConfiguration: {
    OutputLocation: athenaConfig.outputLocation
  },
  WorkGroup: athenaConfig.workGroup
};

const requestBody = JSON.stringify(requestParams);
const requestHash = crypto.createHash('sha256').update(requestBody).digest('hex');

// AWS 签名算法 (简化版本)
const canonicalRequest = [
  'POST',
  '/',
  '',
  `host:athena.${awsConfig.region}.amazonaws.com`,
  `x-amz-date:${timestamp}`,
  `x-amz-target:AmazonAthena.StartQueryExecution`,
  '',
  'host;x-amz-date;x-amz-target',
  requestHash
].join('\n');

const stringToSign = [
  'AWS4-HMAC-SHA256',
  timestamp,
  `${date}/${awsConfig.region}/athena/aws4_request`,
  crypto.createHash('sha256').update(canonicalRequest).digest('hex')
].join('\n');

const signingKey = crypto.createHmac('sha256', `AWS4${awsConfig.secretAccessKey}`)
  .update(date).digest();
const signingKey2 = crypto.createHmac('sha256', signingKey)
  .update(awsConfig.region).digest();
const signingKey3 = crypto.createHmac('sha256', signingKey2)
  .update('athena').digest();
const signingKey4 = crypto.createHmac('sha256', signingKey3)
  .update('aws4_request').digest();

const signature = crypto.createHmac('sha256', signingKey4)
  .update(stringToSign).digest('hex');

const authorization = `AWS4-HMAC-SHA256 Credential=${awsConfig.accessKeyId}/${date}/${awsConfig.region}/athena/aws4_request, SignedHeaders=host;x-amz-date;x-amz-target, Signature=${signature}`;

return {
  json: {
    requestBody,
    timestamp,
    authorization,
    requestHash,
    canonicalRequest,
    stringToSign,
    signature,
    awsConfig
  }
};

// 解析启动查询的响应
const response = $json;

if (response.QueryExecutionId) {
  return {
    json: {
      success: true,
      queryId: response.QueryExecutionId,
      status: 'started',
      message: '查询已启动，正在执行中...',
      timestamp: new Date().toISOString()
    }
  };
} else {
  return {
    json: {
      success: false,
      error: 'Failed to start query',
      response: response,
      status: 'failed',
      timestamp: new Date().toISOString()
    }
  };
}

// 生成检查状态的签名
const crypto = require('crypto');
const { queryId, awsConfig } = $json;
const timestamp = new Date().toISOString().replace(/[\-:]|\.\d{3}/g, '');
const date = timestamp.substr(0, 8);

// 创建检查状态的请求参数
const requestParams = {
  QueryExecutionId: queryId
};

const requestBody = JSON.stringify(requestParams);
const requestHash = crypto.createHash('sha256').update(requestBody).digest('hex');

// AWS 签名算法
const canonicalRequest = [
  'POST',
  '/',
  '',
  `host:athena.${awsConfig.region}.amazonaws.com`,
  `x-amz-date:${timestamp}`,
  `x-amz-target:AmazonAthena.GetQueryExecution`,
  '',
  'host;x-amz-date;x-amz-target',
  requestHash
].join('\n');

const stringToSign = [
  'AWS4-HMAC-SHA256',
  timestamp,
  `${date}/${awsConfig.region}/athena/aws4_request`,
  crypto.createHash('sha256').update(canonicalRequest).digest('hex')
].join('\n');

const signingKey = crypto.createHmac('sha256', `AWS4${awsConfig.secretAccessKey}`)
  .update(date).digest();
const signingKey2 = crypto.createHmac('sha256', signingKey)
  .update(awsConfig.region).digest();
const signingKey3 = crypto.createHmac('sha256', signingKey2)
  .update('athena').digest();
const signingKey4 = crypto.createHmac('sha256', signingKey3)
  .update('aws4_request').digest();

const signature = crypto.createHmac('sha256', signingKey4)
  .update(stringToSign).digest('hex');

const authorization = `AWS4-HMAC-SHA256 Credential=${awsConfig.accessKeyId}/${date}/${awsConfig.region}/athena/aws4_request, SignedHeaders=host;x-amz-date;x-amz-target, Signature=${signature}`;

return {
  json: {
    queryId,
    requestBody,
    timestamp,
    authorization,
    awsConfig
  }
};

// 解析状态响应
const response = $json;
const queryId = response.QueryExecutionId || $('Parse Start Response').item.json.queryId;

if (response.QueryExecution) {
  const execution = response.QueryExecution;
  const status = execution.Status.State;

  return {
    json: {
      queryId,
      status: status.toLowerCase(),
      statusChangeReason: execution.Status.StateChangeReason || '',
      dataScannedInBytes: execution.Statistics?.DataScannedInBytes,
      engineExecutionTimeInMillis: execution.Statistics?.EngineExecutionTimeInMillis,
      timestamp: new Date().toISOString()
    }
  };
} else {
  return {
    json: {
      queryId,
      success: false,
      error: 'Failed to get query status',
      response: response,
      status: 'error',
      timestamp: new Date().toISOString()
    }
  };
}

// 生成获取结果的签名
const crypto = require('crypto');
const { queryId, awsConfig } = $json;
const timestamp = new Date().toISOString().replace(/[\-:]|\.\d{3}/g, '');
const date = timestamp.substr(0, 8);

// 创建获取结果的请求参数
const requestParams = {
  QueryExecutionId: queryId,
  MaxResults: 1000
};

const requestBody = JSON.stringify(requestParams);
const requestHash = crypto.createHash('sha256').update(requestBody).digest('hex');

// AWS 签名算法
const canonicalRequest = [
  'POST',
  '/',
  '',
  `host:athena.${awsConfig.region}.amazonaws.com`,
  `x-amz-date:${timestamp}`,
  `x-amz-target:AmazonAthena.GetQueryResults`,
  '',
  'host;x-amz-date;x-amz-target',
  requestHash
].join('\n');

const stringToSign = [
  'AWS4-HMAC-SHA256',
  timestamp,
  `${date}/${awsConfig.region}/athena/aws4_request`,
  crypto.createHash('sha256').update(canonicalRequest).digest('hex')
].join('\n');

const signingKey = crypto.createHmac('sha256', `AWS4${awsConfig.secretAccessKey}`)
  .update(date).digest();
const signingKey2 = crypto.createHmac('sha256', signingKey)
  .update(awsConfig.region).digest();
const signingKey3 = crypto.createHmac('sha256', signingKey2)
  .update('athena').digest();
const signingKey4 = crypto.createHmac('sha256', signingKey3)
  .update('aws4_request').digest();

const signature = crypto.createHmac('sha256', signingKey4)
  .update(stringToSign).digest('hex');

const authorization = `AWS4-HMAC-SHA256 Credential=${awsConfig.accessKeyId}/${date}/${awsConfig.region}/athena/aws4_request, SignedHeaders=host;x-amz-date;x-amz-target, Signature=${signature}`;

return {
  json: {
    queryId,
    requestBody,
    timestamp,
    authorization,
    awsConfig
  }
};

// 解析查询结果
const response = $json;
const queryId = response.QueryExecutionId || $('Parse Status Response').item.json.queryId;

if (response.ResultSet && response.ResultSet.Rows) {
  const columns = response.ResultSet.ResultSetMetadata?.ColumnInfo?.map(col => col.Name) || [];
  const rows = response.ResultSet.Rows.slice(1).map(row => {
    const rowData = {};
    row.Data.forEach((cell, index) => {
      rowData[columns[index]] = cell.VarCharValue || null;
    });
    return rowData;
  });

  return {
    json: {
      success: true,
      queryId,
      status: 'completed',
      rowCount: rows.length,
      columns,
      data: rows,
      message: `查询成功！返回 ${rows.length} 条记录`,
      timestamp: new Date().toISOString()
    }
  };
} else {
  return {
    json: {
      success: false,
      queryId,
      error: 'Failed to get query results',
      response: response,
      status: 'failed',
      timestamp: new Date().toISOString()
    }
  };
}

// 超时处理
return {
  json: {
    success: false,
    queryId: $('Parse Start Response').item.json.queryId,
    status: 'timeout',
    error: '查询超时',
    message: '查询执行超过5分钟，请检查查询条件或联系管理员',
    timestamp: new Date().toISOString()
  }
};
